// Sprint 60.L Carbon Tier Lock — Mid Carbon is now the production default.
// The previous Standard Carbon (#070809 / #121518 / #171B1F / #1C2026) is
// preserved as a deep-contrast variant for day-of operational surfaces, but
// the working app shell now uses Mid Carbon for grandmother readability +
// breathing room between layers.
// Sprint 60.L Color Lock Pass — locked status palette (matches Figma
// frame 971:7 Token Board on the NGW MOBILE 10+ LOCK page).
// Conventions are aligned with professional event coordination tools:
//   Today    = Steel Blue 500 #6F8794  (neutral date marker)
//   Live     = Bright green #44CB76    (running on schedule)
//   Attention= Muted amber  #D19A55    (watch / standby / due soon)
//   Critical = Rose-red     #E05A63    (overdue / blocking / late)
//   Ready    = Sage green   #4FAE7A    (paid / confirmed / done)
//   Pending  = Steel-gray   #9AA8B3    (inactive / future / neutral)
// CTA gradient is the steel-BLUE brushed-metal #4E6877 → #3F5B6A — the
// New Task button's color. Every primary CTA (incl. marquee New Event)
// inherits this blue; the gray-leaning detour was reverted in Sprint 60.V.
const DARK = {
  bg:       carbonBody,     // Mid Carbon page (palette token)
  surface:  carbonPanel,    // Lifted Carbon card (palette token)
  surface2: carbonSurface2, // Elevated banner (palette token)
  border:   carbonBorder,   // Hairline (palette token)
  // Steel Blue 500 — silvery identity; accent for routes / links / today
  accent:   STEEL.blue500,    // #6F8794
  // Sprint 60.V correction — restore steel-BLUE CTA gradient. Bound to the
  // palette token so a future hue shift moves through one source.
  accentDeep:    steelBlueGradientBottom, // #3F5B6A — primary CTA base
  accentTopGrad: steelBlueGradientTop,    // #4E6877 — gradient top stop
  accentPressed: '#444B4F',   // pressed (was #2C4452)
  accentText:    STEEL.mist300, // #A8B7BF — CTA / link text on dark surfaces
  accentIcon:    STEEL.blue400, // #8BA0AA — icon-default accent
  accent2:  STEEL.blue500,
  text:     textPrimary,
  muted:    textSecondary,
  // Status anchors — bound to palette tokens (sprint-profile pass).
  warn:     amber,        // Attention — honey amber
  danger:   dangerRed,    // Critical — fire red
  success:  successGreen, // Ready — sage green
  live:     '#44CB76', // Live — bright green (running on schedule)
  today:    STEEL.blue500, // Today — Steel Blue 500 (alias)
  pending:  '#9AA8B3', // Pending — steel-gray (inactive / future)
  steel:    STEEL,
  // ── Attention System — 3 contrast tiers (governing view-guiding doctrine) ──
  // Squint at any screen → exactly ONE object (Tier 1) should survive. Most of
  // every screen lives in Tier 2/3. Amplify with SIZE + space, not color.
  tier1:    textPrimary,                // HERO — the one answer per screen (full white, large)
  tier2:    textSecondary,              // EVIDENCE — steel #849eb8, whispers (~60%)
  tier3:    'rgba(132,158,184,0.42)',   // DORMANT — ghost, collapsed/dimmed (~35%)
  tier3Dim: 'rgba(132,158,184,0.28)',   // DORMANT-er — fully at-rest counts / on-track
  // The ONE action object per viewport gets a single 2px left-edge hairline.
  actionEdge: dangerRed,                // accent is a BUDGET, spent once on the most urgent object
};

