const getWorkflowGuidance = (eventType, days) => {
  if (days === null || days < 0) return null;
  const phase = currentPhase(days);
  if (!phase) return null;
  const typeGuide = WORKFLOW_FOCUS[eventType] || WORKFLOW_FOCUS.Birthday;
  if (typeGuide[phase]) return { phase, ...typeGuide[phase] };
  const phaseOrder = Object.keys(PHASE_OFFSET);
  const idx = phaseOrder.indexOf(phase);
  for (let i = Math.max(idx, 0); i < phaseOrder.length; i++) {
    if (typeGuide[phaseOrder[i]]) return { phase, ...typeGuide[phaseOrder[i]] };
  }
  const keys = Object.keys(typeGuide);
  return keys.length ? { phase, ...typeGuide[keys[keys.length - 1]] } : null;
};

const getPhaseActions = (eventType, days, { vendors, timeline, guests }) => {
  const phase = currentPhase(days);
  if (!phase || days === null || days < 0) return [];
  const items = [];

  const hasVenue     = vendors.find(v => v.category === 'Venue'       && STAGES.indexOf(v.status) >= 2);
  const hasCatering  = vendors.find(v => v.category === 'Catering'    && STAGES.indexOf(v.status) >= 2);
  const hasPhoto     = vendors.find(v => v.category === 'Photography' && STAGES.indexOf(v.status) >= 2);
  const invitesDone  = timeline.find(t => t.done && t.task.toLowerCase().includes('invitation'));
  const saveDatesDone = timeline.find(t => t.done && t.task.toLowerCase().includes('save'));
  const confirmed    = guests.filter(g => g.rsvp === 'Yes');
  const unseated     = confirmed.filter(g => !g.table).length;

  if (!hasVenue && ['12 Months Out','10 Months Out'].includes(phase))
    items.push({ level: 'critical', label: 'Venue not booked — Saturday dates fill 12–18 months out', tab: 'Vendors' });
  if (!hasVenue && ['8 Months Out','6 Months Out'].includes(phase))
    items.push({ level: 'warn', label: 'Still no venue — becoming urgent to lock in a date', tab: 'Vendors' });

  if (eventType === 'Wedding') {
    if (!hasPhoto && ['10 Months Out','8 Months Out'].includes(phase))
      items.push({ level: 'warn', label: 'Photographer not yet booked — they fill up fast', tab: 'Vendors' });
    if (!hasCatering && ['10 Months Out','8 Months Out'].includes(phase))
      items.push({ level: 'warn', label: 'No caterer booked — needed early for headcount planning', tab: 'Vendors' });
    if (!saveDatesDone && phase === '8 Months Out')
      items.push({ level: 'warn', label: 'Save-the-dates should go out at 8 months', tab: 'Planning Tasks' });
    if (!invitesDone && ['6 Months Out','4 Months Out'].includes(phase))
      items.push({ level: 'warn', label: 'Formal invitations go out at 6 months — check your timeline', tab: 'Planning Tasks' });
    if (unseated > 0 && ['2 Months Out','1 Month Out','Week Of'].includes(phase))
      items.push({ level: 'warn', label: `Finalize seating — ${unseated} confirmed guest${unseated > 1 ? 's' : ''} still unassigned`, tab: 'Seating' });
  }
  if (isCorporateType(eventType)) {
    const hasAV = vendors.find(v => v.category === 'AV / Tech' && STAGES.indexOf(v.status) >= 2);
    if (!hasAV && ['3 Months Out','2 Months Out'].includes(phase))
      items.push({ level: 'warn', label: 'AV / Tech vendor not booked — critical for corporate events', tab: 'Vendors' });
  }
  if (!hasCatering && phase === 'Week Of')
    items.push({ level: 'critical', label: 'No caterer confirmed for event day — escalate immediately', tab: 'Vendors' });

  return items;
};

// ─── Unicode-safe base64 (handles ✓, em-dashes, accents, emoji in brief data) ──
const b64encode = (str) => {
  const bytes = new TextEncoder().encode(str);
  let bin = '';
  bytes.forEach(b => { bin += String.fromCharCode(b); });
  return btoa(bin);
};
const b64decode = (b64) => {
  const bin = atob(b64);
  const bytes = Uint8Array.from(bin, c => c.charCodeAt(0));
  return new TextDecoder().decode(bytes);
};

// ─── Branded letterhead / footer for printed & exported client materials ──────
const brandAccent = (profile) => (profile?.brandColor && /^#[0-9a-fA-F]{3,8}$/.test(profile.brandColor)) ? profile.brandColor : defaultBrandColor;
const brandLetterheadHTML = (profile) => {
  if (!profile) return '';
  const esc = (s) => String(s || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
  const accent  = brandAccent(profile);
  const name    = esc(profile.businessName || profile.name || '');
  const logoImg = profile.logo ? `<img src="${profile.logo}" alt="" style="max-height:56px;max-width:190px;object-fit:contain"/>` : '';
  if (!name && !logoImg) return '';
  // City + State (board/user 2026-06-12). If the saved city already ends in ", ST"
  // don't double it. Phone is formatted; email shown as entered (trimmed).
  const cityRaw   = String(profile.city || '').trim();
  const st        = String(profile.state || '').trim();
  const cityState = (cityRaw && st && !new RegExp(`,\\s*${st}$`, 'i').test(cityRaw)) ? `${cityRaw}, ${st}` : cityRaw;
  const phoneFmt  = profile.phone ? formatPhone(profile.phone) : '';
  const emailFmt  = profile.email ? String(profile.email).trim() : '';
  const contact = [phoneFmt, emailFmt, profile.website].filter(Boolean).map(esc);
  return `<div style="display:flex;align-items:center;justify-content:space-between;gap:16px;border-bottom:3px solid ${accent};padding-bottom:14px;margin-bottom:22px;font-family:-apple-system,system-ui,Arial,sans-serif">
    <div style="display:flex;align-items:center;gap:14px">${logoImg}
      <div>${name ? `<div style="font-size:18px;font-weight:800;color:#111;letter-spacing:-0.01em">${name}</div>` : ''}
        ${cityState ? `<div style="font-size:12px;color:#777;margin-top:2px">${esc(cityState)}</div>` : ''}</div></div>
    ${contact.length ? `<div style="font-size:11px;color:#555;text-align:right;line-height:1.7">${contact.map(c => `<div>${c}</div>`).join('')}</div>` : ''}
  </div>`;
};
const brandPaymentFooterHTML = (profile) => {
  if (!profile) return '';
  const esc = (s) => String(s || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
  const accent = brandAccent(profile);
  const parts = [];
  if (profile.venmo)  parts.push(`Venmo ${esc(profile.venmo)}`);
  if (profile.zelle)  parts.push(`Zelle ${esc(profile.zelle)}`);
  if (profile.paypal) parts.push(`PayPal ${esc(profile.paypal)}`);
  if (profile.acceptsCash)  parts.push('Cash');
  if (profile.acceptsCheck) parts.push('Check');
  // Contract floor (board 2026-06-12): deposit %, payment schedule, cancellation/
  // refund terms, and the legal billing entity print here on the client invoice —
  // the real consumer that keeps these Settings fields honest (not dead fields).
  const terms = [];
  if (profile.depositPct)      terms.push(`${esc(profile.depositPct)}% deposit to book`);
  if (profile.paymentSchedule) terms.push(esc(profile.paymentSchedule));
  const cancel = profile.cancellationTerms ? esc(profile.cancellationTerms) : '';
  const fullAddr = [profile.address, profile.addressCityStateZip].filter(Boolean).join(', ');
  const legalLine = [profile.legalName, fullAddr, profile.taxId && `EIN ${profile.taxId}`].filter(Boolean).map(esc).join('  ·  ');
  if (parts.length === 0 && terms.length === 0 && !cancel && !legalLine) return '';
  const block = (label, body) => `<div style="margin-bottom:8px"><div style="font-size:10px;font-weight:700;letter-spacing:0.08em;text-transform:uppercase;color:${accent};margin-bottom:4px">${label}</div><div style="font-size:12px;color:#444;line-height:1.5">${body}</div></div>`;
  return `<div style="margin-top:28px;padding-top:14px;border-top:1px solid #ddd;font-family:-apple-system,system-ui,Arial,sans-serif">
    ${parts.length ? block('Payment Options', parts.join('  ·  ')) : ''}
    ${terms.length ? block('Payment Terms', terms.join('  ·  ')) : ''}
    ${cancel ? block('Cancellation &amp; Refund', cancel) : ''}
    ${legalLine ? `<div style="font-size:10.5px;color:#999;margin-top:10px">${legalLine}</div>` : ''}
  </div>`;
};

// ─── Field validation helpers ─────────────────────────────────────────────────
const isEmail   = v => !v || /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(v.trim());
const isPhone = v => !v || (() => { const d = v.replace(/\D/g, ''); return d.length >= 10 && d.length <= 15; })();
const isUrl     = v => !v || /^(https?:\/\/)?[\w.-]+\.[a-z]{2,}/.test(v.trim());

// Auto-format phone to (XXX) XXX-XXXX as the user types (US).
// Passes through non-US numbers (11+ raw digits keep their digits).
const formatPhone = (raw = '') => {
  const d = raw.replace(/\D/g, '').slice(0, 10); // strip non-digits, cap at 10
  if (!d)            return '';
  if (d.length <= 3) return `(${d}`;
  if (d.length <= 6) return `(${d.slice(0,3)}) ${d.slice(3)}`;
  return `(${d.slice(0,3)}) ${d.slice(3,6)}-${d.slice(6)}`;
};
const isPosDollar = v => v === '' || v === undefined || v === null || (!isNaN(Number(v)) && Number(v) >= 0);


// ─── Constants ───────────────────────────────────────────────────────────────
const STAGES    = ['Considering', 'Quoted', 'Contracted', 'Deposit Paid', 'Confirmed'];

// ─── Canonical vendor money model (single source of truth) ─────────────────────
// A vendor is "committed" once Contracted or further along the stage ladder.
// PAID  = deposit (only if actually paid) + balance (only if marked paid).
// BALANCE DUE = cost − paid, floored at 0. Counting the deposit only when
// depositPaid is true is what keeps the math honest: an unpaid deposit still
// means you owe the full cost. Every "balance due / owed to vendors" figure in
// the app should route through these so the numbers always reconcile.
const vendorIsCommitted = (v) => STAGES.indexOf(v.status) >= 2;
const vendorPaid        = (v) => v.balancePaid ? (v.cost || 0) : (v.depositPaid ? (v.depositAmt || 0) : 0);
const vendorBalance     = (v) => Math.max(0, (v.cost || 0) - vendorPaid(v));

// ─── Sprint 60.A: first-run signals (local-only, not analytics theater) ────
// Records timestamps of real product milestones so we can later judge
// whether onboarding actually works. Plain localStorage; no PII; no
// network. Reads/writes are idempotent — the first occurrence wins.
//
// Keys we record:
//   firstAppOpenAt      — first time App component mounted
//   firstEventCreatedAt — first real (non-sample) event created
//   firstClientCreatedAt — first client created
//   firstPipelineViewedAt — first time Pipeline L1 opened
//   firstSampleLoadedAt — first time sample data was loaded
//   onboardingPath      — 'real_event' | 'sample_event' | 'client_first' | 'unknown'
const FIRST_RUN_KEY = 'ngw-firstrun-signals';
const readFirstRunSignals = () => {
  try { return JSON.parse(localStorage.getItem(FIRST_RUN_KEY) || '{}'); }
  catch { return {}; }
};
const recordFirstRunSignal = (key, value) => {
  try {
    const cur = readFirstRunSignals();
    if (cur[key] != null && value == null) return; // idempotent — don't overwrite a timestamp
    const next = { ...cur, [key]: value != null ? value : new Date().toISOString() };
    localStorage.setItem(FIRST_RUN_KEY, JSON.stringify(next));
  } catch {}
};
// Committed contract value = total cost of vendors that are Contracted+.
const vendorCommittedCost = (v) => vendorIsCommitted(v) ? (v.cost || 0) : 0;

// ─── Sprint 59C: payment status color discipline ─────────────────────────────
// Locks the semantic map called out in the Sprint 59A audit and the Sprint 59C
// prompt: green = paid/done, red = overdue/broken, amber = actionable risk
// (due ≤30 days), neutral steel = no due date / future. Stops `C.muted` from
// painting every "money still owed" state amber regardless of urgency.
//
// `daysUntilDue` is the integer day delta to the soonest unpaid due date in
// the row's scope (a single vendor, or the soonest of all category-linked
// vendors). Pass `null` when no due date is known — the row stays neutral.
const paymentStatusColor = (C, paid, daysUntilDue) => {
  if (paid) return C.success;
  if (typeof daysUntilDue !== 'number') return C.muted;
  if (daysUntilDue < 0)   return C.danger;
  if (daysUntilDue <= 30) return C.muted;
  return C.muted;
};
// Find the soonest unpaid `payDueDate` across a category's committed vendors.
// Returns `null` when nothing in scope has a due date — the caller paints
// the row neutral instead of falsely warning.
const soonestUnpaidDueDays = (vendors, category) => {
  if (!Array.isArray(vendors) || !category) return null;
  const days = vendors
    .filter(v => (v.budgetCategory || v.category) === category)
    .filter(vendorIsCommitted)
    .filter(v => !v.balancePaid)
    .map(v => v.payDueDate ? daysUntil(v.payDueDate) : null)
    .filter(d => d !== null);
  if (!days.length) return null;
  return Math.min(...days);
};
// Color maps are now functions so they react to the active theme token set.
// Usage inside components: const stageCLR = STAGE_CLR(C); stageCLR['Confirmed']
const STAGE_CLR = (C) => ({ Considering: C.muted, Quoted: C.muted, Contracted: C.accent2, 'Deposit Paid': C.accent, Confirmed: C.success });

// ─── Vendor-1: operational reliability (transparent, data-gated — never faked) ──
const _clamp = (n, lo, hi) => Math.max(lo, Math.min(hi, n));
const _hasField = (v, k) => v && v[k] !== undefined && v[k] !== null && v[k] !== '';
const VENDOR_TIERS = ['Standard', 'Preferred', 'Elite', 'Certified'];
const VENDOR_TIER_META = {
  Standard:  { color: '#9090a8', icon: '○', label: 'Standard'  },
  Preferred: { color: '#60a5fa', icon: '◆', label: 'Preferred' },
  Elite:     { color: '#a78bfa', icon: '★', label: 'Elite'     },
  Certified: { color: '#34d399', icon: '✓', label: 'Certified' },
};

// Returns { sufficient, score (0–100 or null), reason }. Only scores with a real track record.
function vendorReliabilityScore(v = {}) {
  const ec = Number(v.eventsCompleted);
  const qualitySignals = ['onTimeRate', 'successfulEventCount', 'plannerRehireCount', 'avgResponseHours'].filter(k => _hasField(v, k));
  if (!_hasField(v, 'eventsCompleted') || !(ec > 0) || qualitySignals.length === 0) {
    return { sufficient: false, score: null, reason: 'Insufficient data' };
  }
  let pts = 0, max = 0;
  if (_hasField(v, 'onTimeRate'))         { max += 30; pts += _clamp(Number(v.onTimeRate), 0, 100) / 100 * 30; }
  if (_hasField(v, 'avgResponseHours'))   { max += 20; pts += _clamp((48 - Math.max(0, Number(v.avgResponseHours))) / 46, 0, 1) * 20; }
  max += 15; pts += _clamp(ec / 100, 0, 1) * 15; // experience (ec>0 guaranteed)
  if (_hasField(v, 'plannerRehireCount')) { max += 15; pts += _clamp(Number(v.plannerRehireCount) / 5, 0, 1) * 15; }
  if (_hasField(v, 'successfulEventCount')) { max += 10; pts += _clamp(Number(v.successfulEventCount) / ec, 0, 1) * 10; }
  let score = (pts / max) * 100;
  // Penalties scale with how often problems happen per event
  if (_hasField(v, 'cancellationCount')) score -= _clamp(Number(v.cancellationCount) / ec, 0, 1) * 30;
  if (_hasField(v, 'incidentCount'))     score -= _clamp(Number(v.incidentCount) / ec, 0, 1) * 30;
  return { sufficient: true, score: Math.round(_clamp(score, 0, 100)), reason: '' };
}

// Field-driven badges — never assigned without the underlying data.
function vendorBadges(v = {}) {
  const out = [];
  const ec = Number(v.eventsCompleted);
  const { sufficient, score } = vendorReliabilityScore(v);
  if (_hasField(v, 'avgResponseHours') && Number(v.avgResponseHours) <= 4)                         out.push('Fast Responder');
  if (_hasField(v, 'plannerRehireCount') && Number(v.plannerRehireCount) >= 2)                     out.push('Planner Trusted');
  if (sufficient && score >= 85)                                                                   out.push('High Reliability');
  if (_hasField(v, 'eventsCompleted') && ec >= 100)                                                out.push('100+ Events Completed');
  if (_hasField(v, 'onTimeRate') && Number(v.onTimeRate) >= 95)                                    out.push('Excellent Timeline Adherence');
  if (_hasField(v, 'cancellationCount') && Number(v.cancellationCount) === 0 && ec >= 5)           out.push('Zero Cancellation Vendor');
  if (_hasField(v, 'avgResponseHours') && Number(v.avgResponseHours) <= 8 && _hasField(v, 'onTimeRate') && Number(v.onTimeRate) >= 85) out.push('Strong Communication');
  if (_hasField(v, 'incidentCount') && Number(v.incidentCount) === 0 && _hasField(v, 'successfulEventCount') && Number(v.successfulEventCount) >= 10) out.push('Consistent Delivery');
  return out;
}

// Earned tier. Certified is manual-only (cannot be earned/bought in this phase).
function vendorTier(v = {}) {
  if (v.certified === true || v.preferredTier === 'Certified') return 'Certified';
  const { sufficient, score } = vendorReliabilityScore(v);
  if (!sufficient) return 'Standard';
  const ec = Number(v.eventsCompleted) || 0;
  const rehire = Number(v.plannerRehireCount) || 0;
  if (score >= 90 && rehire >= 3 && ec >= 50) return 'Elite';
  if (score >= 75 && ec >= 10)                return 'Preferred';
  return 'Standard';
}

// ─── Sprint 60.Y — Vendor Bank intelligence surfacing ──────────────────────────
// Score breakdown: the six weighted signals with raw value + point contribution,
// so the reliability number is never a black box. Mirrors vendorReliabilityScore.
function vendorScoreBreakdown(v = {}) {
  const ec = Number(v.eventsCompleted);
  if (!_hasField(v, 'eventsCompleted') || !(ec > 0)) return [];
  const rows = [];
  if (_hasField(v, 'onTimeRate'))           rows.push({ key: 'onTime',  label: 'On-time rate',  raw: `${_clamp(Number(v.onTimeRate), 0, 100)}%`, points: Math.round(_clamp(Number(v.onTimeRate), 0, 100) / 100 * 30), max: 30 });
  if (_hasField(v, 'avgResponseHours'))     rows.push({ key: 'reply',   label: 'Response time', raw: `${Number(v.avgResponseHours)}h`,            points: Math.round(_clamp((48 - Math.max(0, Number(v.avgResponseHours))) / 46, 0, 1) * 20), max: 20 });
  rows.push({ key: 'exp', label: 'Experience', raw: `${ec} events`, points: Math.round(_clamp(ec / 100, 0, 1) * 15), max: 15 });
  if (_hasField(v, 'plannerRehireCount'))   rows.push({ key: 'rehire',  label: 'You rehired',   raw: `${Number(v.plannerRehireCount)}×`,          points: Math.round(_clamp(Number(v.plannerRehireCount) / 5, 0, 1) * 15), max: 15 });
  if (_hasField(v, 'successfulEventCount')) rows.push({ key: 'success', label: 'Went well',     raw: `${Number(v.successfulEventCount)}/${ec}`,   points: Math.round(_clamp(Number(v.successfulEventCount) / ec, 0, 1) * 10), max: 10 });
  if (_hasField(v, 'incidentCount') && Number(v.incidentCount) > 0) rows.push({ key: 'incidents', label: 'Incidents', raw: `${Number(v.incidentCount)}`, points: -Math.round(_clamp(Number(v.incidentCount) / ec, 0, 1) * 30), max: 0, penalty: true });
  return rows;
}

// Trust badge — a plain-language read on the performance score (distinct from
// the earned tier). TRUSTED (proven + strong), STEADY (solid), WATCH (needs
// attention / has an incident), NEW (not enough record to score).
function vendorTrustBadge(v = {}) {
  const { sufficient, score } = vendorReliabilityScore(v);
  if (!sufficient) return { label: 'NEW', tone: 'muted' };
  const incidents = _hasField(v, 'incidentCount') ? Number(v.incidentCount) : 0;
  if (score >= 85 && incidents === 0) return { label: 'TRUSTED', tone: 'success' };
  if (score < 70 || incidents > 0)    return { label: 'WATCH',   tone: 'warn' };
  return { label: 'STEADY', tone: 'accent' };
}

// Event specialties derived from the planner's OWN booking history (never
// self-claimed): count completed events of each type where this bank vendor
// appears (matched by name). BEST = the highest count. A stored `specialties`
// array (e.g. seeded sample data) takes precedence when present.
function vendorSpecialtiesFromHistory(vendor, events = []) {
  if (Array.isArray(vendor?.specialties) && vendor.specialties.length) return vendor.specialties;
  if (!vendor?.name) return [];
  const vn = vendor.name.trim().toLowerCase();
  const counts = {};
  (events || []).forEach(ev => {
    const t = ev.type || ev.eventType;
    if (!t) return;
    if ((ev.vendors || []).some(x => (x?.name || '').trim().toLowerCase() === vn)) counts[t] = (counts[t] || 0) + 1;
  });
  const rows = Object.entries(counts).map(([type, count]) => ({ type, count })).sort((a, b) => b.count - a.count);
  if (rows.length) rows[0].isBest = true;
  return rows;
}

// Referral provenance — rates the SOURCE of the recommendation, separate from
// the performance score. Levels in descending trust.
const REFERRAL_LEVELS = {
  'network-trusted': { label: 'NETWORK-TRUSTED', tone: 'success', blurb: 'Multiple planners in your NGW network have booked them. Highest provenance.' },
  'peer-referred':   { label: 'PEER-REFERRED',   tone: 'accent',  blurb: 'One planner you follow referred them. Solid, but a single source.' },
  'client-referred': { label: 'CLIENT-REFERRED', tone: 'muted',   blurb: 'Came from a client, not a peer — good signal, less operational insight.' },
  'self-added':      { label: 'SELF-ADDED',      tone: 'warn',    blurb: 'No external corroboration yet. Verify insurance + references before booking.' },
};
const REFERRAL_ORDER = ['network-trusted', 'peer-referred', 'client-referred', 'self-added'];
const referralMeta = (source) => REFERRAL_LEVELS[source] || REFERRAL_LEVELS['self-added'];

// Cross-event vendor library: dedup by name+category, keep richest operational record, count repeat use.
function aggregateVendorLibrary(events = []) {
  const opFields = ['eventsCompleted', 'onTimeRate', 'avgResponseHours', 'cancellationCount', 'incidentCount', 'plannerRehireCount', 'successfulEventCount'];
  const countOp = (v) => opFields.filter(f => _hasField(v, f)).length;
  const map = new Map();
  (events || []).forEach(ev => (ev.vendors || []).forEach(v => {
    if (!v || !v.name) return;
    const key = `${v.name.trim().toLowerCase()}|${(v.category || '').toLowerCase()}`;
    const cur = map.get(key);
    if (!cur) map.set(key, { vendor: v, eventsLinked: 1 });
    else { cur.eventsLinked += 1; if (countOp(v) > countOp(cur.vendor)) cur.vendor = v; }
  }));
  return [...map.values()].map(({ vendor, eventsLinked }) => ({ ...vendor, eventsLinked }));
}

