// ─── Shared components ────────────────────────────────────────────────────────

// Sprint 58: shared Avatar component. Renders an image when present
// (profile.headshot / vendor.thumbnail / client.thumbnail), else falls back
// to colored initials. Sizes are caller-controlled so the same component
// fits both a 28px top-bar pill and a 56px modal header.
function Avatar({ src, name, size = 32, color, title }) {
  const C = useT();
  const dim = size;
  const initials = (name || '?')
    .split(/\s+/).filter(Boolean).slice(0, 2)
    .map(w => w[0]).join('').toUpperCase();
  const bg = color || C.accent2 || '#3a8a62';
  const fontSize = Math.max(9, Math.round(dim * 0.36));
  if (src) {
    return (
      <img src={src} alt={name || ''} title={title || name || ''}
        style={{
          width: dim, height: dim, borderRadius: '50%',
          objectFit: 'cover', flexShrink: 0,
          border: `1px solid ${C.border}`,
          background: C.surface,
        }} />
    );
  }
  return (
    <div title={title || name || ''} style={{
      width: dim, height: dim, borderRadius: '50%',
      background: bg, color: '#fff',
      display: 'flex', alignItems: 'center', justifyContent: 'center',
      flexShrink: 0, fontSize, fontWeight: 700, letterSpacing: '0.02em',
      border: `1px solid ${bg}`,
    }}>
      {initials || '?'}
    </div>
  );
}

// Sprint 58: shared image-upload helper. Captures a file via the standard
// <input type="file">, downscales to ≤max px, encodes as dataURL, hands the
// result back via onChange(dataURL). Mirrors the ProfileModal logo-upload
// pattern so every modal that wants a thumbnail can drop this in.
function ImageUpload({ value, label, onChange, onError, size = 48, max = 400, hint }) {
  const C = useT();
  const inputRef = useRef(null);
  const [err, setErr] = useState('');
  const handle = (e) => {
    const file = e.target.files?.[0];
    if (!file) return;
    if (!file.type.startsWith('image/')) {
      const m = 'Please choose an image file.';
      setErr(m); onError?.(m); return;
    }
    setErr('');
    const reader = new FileReader();
    reader.onload = (ev) => {
      const img = new Image();
      img.onload = () => {
        let { width, height } = img;
        if (width > max || height > max) {
          const sc = max / Math.max(width, height);
          width = Math.round(width * sc);
          height = Math.round(height * sc);
        }
        const canvas = document.createElement('canvas');
        canvas.width = width; canvas.height = height;
        canvas.getContext('2d').drawImage(img, 0, 0, width, height);
        try {
          const dataUrl = canvas.toDataURL('image/jpeg', 0.85);
          onChange?.(dataUrl);
        } catch {
          const m = 'That image is too large to save. Try a smaller file.';
          setErr(m); onError?.(m);
        }
      };
      img.onerror = () => {
        const m = 'Could not read that image.';
        setErr(m); onError?.(m);
      };
      img.src = ev.target.result;
    };
    reader.readAsDataURL(file);
  };
  return (
    <div style={{ display: 'flex', alignItems: 'center', gap: 10, flexWrap: 'wrap' }}>
      <Avatar src={value} name={label || ''} size={size} />
      <div style={{ display: 'flex', flexDirection: 'column', gap: 4 }}>
        <div style={{ display: 'flex', gap: 6, alignItems: 'center' }}>
          <input ref={inputRef} type="file" accept="image/*" onChange={handle} style={{ display: 'none' }} />
          <button type="button"
            onClick={() => inputRef.current?.click()}
            style={{
              padding: '5px 12px', borderRadius: 8,
              border: `1px solid ${C.border}`, background: 'transparent',
              color: C.text, cursor: 'pointer', fontSize: 11, fontWeight: 600,
              fontFamily: 'inherit',
            }}>
            {value ? 'Replace' : 'Upload'}
          </button>
          {value && (
            <button type="button" onClick={() => onChange?.(null)}
              style={{
                padding: '5px 12px', borderRadius: 8,
                border: `1px solid ${C.border}`, background: 'transparent',
                color: C.muted, cursor: 'pointer', fontSize: 11, fontWeight: 500,
                fontFamily: 'inherit',
              }}>
              Remove
            </button>
          )}
        </div>
        {(hint || err) && (
          <div style={{ fontSize: 10, color: err ? C.danger : C.muted, lineHeight: 1.4 }}>
            {err || hint}
          </div>
        )}
      </div>
    </div>
  );
}

function StatCard({ label, value, sub, color, onClick, tier }) {
  const C  = useT();
  const s  = makeS(C);
  const bp = useContext(BpCtx);
  const isMobile = bp === 'mobile' || bp === 'tablet';
  // Attention System: on a strip that already has a hero, every StatCard is
  // EVIDENCE — demoted number + steel, so the one hero survives the squint.
  const isEvidence = tier === 'evidence';
  const numSize = isEvidence ? (isMobile ? 22 : 26) : (isMobile ? 32 : 36);
  const numColor = isEvidence ? (color || C.tier2) : color;
  const hue = color || C.accent;
  // Sprint 51 a11y: keyboard handler so role="button" actually behaves like
  // one. Enter and Space both fire the click — matches native <button>.
  const onKeyDown = onClick ? (e) => {
    if (e.key === 'Enter' || e.key === ' ') {
      e.preventDefault();
      onClick();
    }
  } : undefined;
  return (
    <div onClick={onClick}
      role={onClick ? 'button' : undefined}
      tabIndex={onClick ? 0 : undefined}
      aria-label={onClick ? `${label}: ${value}` : undefined}
      onKeyDown={onKeyDown}
      style={{
        flex: 1, minWidth: isMobile ? 0 : 130,
        flexBasis: isMobile ? 'calc(50% - 6px)' : 'auto',
        padding: '16px 18px 14px',
        cursor: onClick ? 'pointer' : 'default',
        borderRadius: 10,
        border: `1px solid transparent`,
        // Left status "eyebrow" — follows the status rules: the strip is the card's
        // own status color (red at-risk / amber approaching / green on-track / steel
        // neutral). This is a status object, not a decorative accent.
        borderLeft: `3px solid ${color || C.muted}`,
        transition: 'background 0.12s, border-color 0.12s',
        background: 'transparent',
        boxSizing: 'border-box',
        animation: 'orchNumIn 0.35s ease both',
      }}
      onMouseEnter={onClick ? (e => {
        e.currentTarget.style.background = hue + '0c';
        e.currentTarget.style.borderColor = hue + '33';
      }) : undefined}
      onMouseLeave={onClick ? (e => {
        e.currentTarget.style.background = 'transparent';
        e.currentTarget.style.borderColor = 'transparent';
      }) : undefined}
    >
      <div style={s.editLabel}>{label}</div>
      <div style={{ ...s.glanceNum(numSize, numColor), marginTop: 8, marginBottom: 4 }}>{value}</div>
      {sub && <div style={{ fontSize: 11, color: isEvidence ? C.tier3 : C.muted, lineHeight: 1.35, marginTop: 2 }}>{sub}</div>}
      {onClick && <div style={{ fontSize: 10, color: hue, opacity: 0.6, marginTop: 6, letterSpacing: '0.04em' }}>Open ↗</div>}
    </div>
  );
}

// Fixed-height KPI cell that lists rows internally (desktop "inbox" KPIs:
// Task Inbox, Due Soon, Action Required). Header + scrollable body.
function KpiInboxPanel({ label, headerRight, hasItems, empty, children }) {
  const C = useT();
  const s = makeS(C);
  return (
    <div style={{ ...s.card, marginBottom: 0, padding: 0, overflow: 'hidden', display: 'flex', flexDirection: 'column', height: 150 }}>
      <div style={{ padding: '13px 16px 10px', borderBottom: hasItems ? `1px solid ${C.border}` : 'none', flexShrink: 0, display: 'flex', alignItems: 'baseline', justifyContent: 'space-between', gap: 8 }}>
        <div style={{ fontSize: 11, fontWeight: 600, textTransform: 'uppercase', letterSpacing: '0.1em', color: C.muted, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{label}</div>
        {headerRight}
      </div>
      <div style={{ overflowY: 'auto', flex: 1 }}>
        {hasItems ? children : <div style={{ padding: '16px', fontSize: 13, color: C.muted }}>{empty}</div>}
      </div>
    </div>
  );
}

function budgetBarColor(pct, C) {
  if (pct > 100)  return C.danger;  // over budget — crimson
  if (pct >= 90)  return C.muted;    // at/nearly budget — amber (theme-aware)
  if (pct >= 75)  return C.muted;    // getting close — amber
  return C.success;                 // on track — green
}
// Attribute tags — multi-select toggle chips (set on a vendor) and a compact
// read-only display variant for cards.
function TagChips({ value = [], onChange, options = VENDOR_TAGS }) {
  const C = useT();
  const set = Array.isArray(value) ? value : [];
  const toggle = (t) => onChange(set.includes(t) ? set.filter(x => x !== t) : [...set, t]);
  return (
    <div style={{ display: 'flex', flexWrap: 'wrap', gap: 6 }}>
      {options.map(t => {
        const on = set.includes(t);
        return (
          <button type="button" key={t} onClick={() => toggle(t)} aria-pressed={on}
            style={{
              padding: '6px 11px', borderRadius: 999, fontSize: 11.5, fontWeight: on ? 700 : 500,
              minHeight: 34, cursor: 'pointer', fontFamily: 'inherit',
              border: `1px solid ${on ? C.accent : C.border}`,
              background: on ? C.accent + '1c' : 'transparent',
              color: on ? C.accent : C.muted,
            }}>
            {on ? '✓ ' : ''}{t}
          </button>
        );
      })}
    </div>
  );
}

function TagBadges({ tags }) {
  const C = useT();
  const list = Array.isArray(tags) ? tags : [];
  if (!list.length) return null;
  return (
    <div style={{ display: 'flex', flexWrap: 'wrap', gap: 4, marginTop: 6 }}>
      {list.map(t => (
        <span key={t} style={{
          fontSize: 9.5, fontWeight: 700, color: C.accent2 || C.accent,
          background: (C.accent2 || C.accent) + '18', border: `1px solid ${(C.accent2 || C.accent)}44`,
          borderRadius: 999, padding: '1px 7px', whiteSpace: 'nowrap',
        }}>{t}</span>
      ))}
    </div>
  );
}

// PL-15 (board: "say it in words, not a chart") — readiness trend as a WORDED
// chip, not a 52×14 sparkline. The tiny chart was illegible (only up/down read)
// and meaningless to a non-technical user (grandmother test). The same honest
// history drives a plain trend word + delta: ↗ Improving N · ↘ Slipping N · →
// Steady. Hidden until there are 2+ real points (no fake trend).
function ReadinessSparkline({ eventId }) {
  const C = useT();
  const hist = getReadinessHistory(eventId);
  if (!hist || hist.length < 2) return null;
  const pts   = hist.map(p => p.s);
  const trend = pts[pts.length - 1] - pts[0];
  const up = trend > 0, down = trend < 0;
  const col   = up ? C.success : down ? C.warn : C.muted;
  const arrow = up ? '↗' : down ? '↘' : '→';
  // PL-15b (board: "Improving 12 — 12 what?"): the delta is a DIRECTION signal,
  // not a metric. Don't attribute a number to it — a bare "12" reads as a mystery
  // count and invites false precision. Say only which way readiness is moving.
  const plain = up   ? 'More ready'
              : down ? 'Less ready'
              :        'Holding steady';
  return (
    <span
      title={`Readiness is ${up ? 'trending up' : down ? 'trending down' : 'holding steady'}. Updates only when the score actually moves.`}
      aria-label={`Readiness ${up ? 'trending up, more ready' : down ? 'trending down, less ready' : 'holding steady'}`}
      style={{ display: 'inline-flex', alignItems: 'center', gap: 4, flexShrink: 0, fontSize: 10.5, fontWeight: 700, color: col, letterSpacing: '0.02em', whiteSpace: 'nowrap' }}>
      <span aria-hidden style={{ fontSize: 12, lineHeight: 1 }}>{arrow}</span>
      {plain}
    </span>
  );
}

function ProgressBar({ pct, color }) {
  const C          = useT();
  const isLight    = C.surface === '#ffffff';
  const clampedPct = Math.min(pct, 100);
  const fill       = color || budgetBarColor(pct, C);
  return (
    <div style={{
      height: 8, borderRadius: 99, minWidth: 80, overflow: 'hidden', position: 'relative',
      // Inset groove — top-heavy dark overlay makes it read as a carved channel
      background: isLight
        ? `linear-gradient(180deg, rgba(0,0,0,0.10) 0%, transparent 55%), ${C.surface2}`
        : `linear-gradient(180deg, rgba(0,0,0,0.35) 0%, rgba(0,0,0,0.12) 55%, transparent 100%), ${C.surface2}`,
      boxShadow: isLight
        ? 'inset 0 1px 3px rgba(0,0,0,0.14), inset 0 1px 1px rgba(0,0,0,0.08)'
        : 'inset 0 2px 4px rgba(0,0,0,0.40), inset 0 1px 2px rgba(0,0,0,0.25)',
    }}>
      <div style={{
        height: '100%', width: clampedPct + '%', borderRadius: 99, transition: 'width 0.4s ease',
        // Convex cylinder — white specular cap at top, shadow-side at base
        background: [
          'linear-gradient(180deg, rgba(255,255,255,0.40) 0%, rgba(255,255,255,0.10) 40%, rgba(0,0,0,0.00) 55%, rgba(0,0,0,0.12) 100%)',
          fill,
        ].join(', '),
      }} />
    </div>
  );
}

// ─── Voice Button ─────────────────────────────────────────────────────────────

// Evaluated once at module load — avoids per-render property lookup
const SR = window.SpeechRecognition || window.webkitSpeechRecognition;

function VoiceButton({ onResult, style }) {
  const C = useT();
  const toast = useToast();
  const [active, setActive] = useState(false);
  const recRef = useRef(null);
  if (!SR) return null;

  // The Web Speech API only works in a secure context (HTTPS or localhost).
  // Over a plain-HTTP LAN IP (e.g. a phone hitting http://10.x.x.x:3000) the
  // browser silently blocks the mic — so say so instead of looking broken.
  const secure = typeof window !== 'undefined' && (window.isSecureContext || /^localhost$|^127\.|^\[::1\]$/.test(window.location.hostname));

  const toggle = () => {
    if (active) {
      recRef.current?.stop();
      setActive(false);
      return;
    }
    if (!secure) {
      toast('Voice needs a secure connection — open the live site (https://) or localhost. It can’t use the mic over a plain http:// address.');
      return;
    }
    const rec = new SR();
    rec.continuous = false;
    rec.interimResults = false;
    rec.onresult = (e) => {
      const t = e.results[0]?.[0]?.transcript || '';
      if (t) onResult(t);
      setActive(false);
    };
    rec.onerror = (e) => {
      setActive(false);
      const reason = e?.error === 'not-allowed' || e?.error === 'service-not-allowed'
        ? 'Microphone permission was blocked. Allow mic access in your browser, then try again.'
        : e?.error === 'no-speech' ? 'Didn’t catch anything — tap the mic and speak.'
        : e?.error === 'audio-capture' ? 'No microphone found.'
        : 'Voice input didn’t start. Check mic permissions and try again.';
      toast(reason);
    };
    rec.onend   = () => setActive(false);
    try {
      rec.start();
      recRef.current = rec;
      setActive(true);
    } catch (err) {
      setActive(false);
      toast('Voice input couldn’t start. Tap the mic again.');
    }
  };

  return (
    <button type="button" onClick={toggle} title={active ? 'Stop recording' : 'Dictate note'}
      style={{ flexShrink: 0, padding: '5px 9px', borderRadius: 6, border: 'none', cursor: 'pointer', fontSize: 14, lineHeight: 1,
        background: active ? C.danger + '22' : C.border, color: active ? C.danger : C.muted,
        transition: 'all 0.15s', ...style }}>
      {active ? '■' : 'Mic'}
    </button>
  );
}

// ─── Draft Versions ───────────────────────────────────────────────────────────
// Reusable version bar for ANY draft surface (proposal, schedule, document,
// message). Pass a stable `draftKey`, the current `content` (string or array),
// and `onRestore(content)` to load a chosen version back into the surface.
// "Save version" snapshots the current content; each pill restores; pencil
// renames; ✕ deletes. Backed by lib/draftVersions (localStorage).
function DraftVersionBar({ draftKey, content, onRestore, saveLabel = 'Save version', emptyHint = 'No saved versions yet — save one to keep alternatives.' }) {
  const C = useT();
  const [, setTick] = useState(0);
  const force = () => setTick(t => t + 1);
  if (!draftKey) return null;
  const versions = dvList(draftKey);
  const activeId = dvActiveId(draftKey);

  const hasContent = content != null && (
    typeof content === 'string' ? content.trim().length > 0
      : Array.isArray(content) ? content.length > 0 : true
  );

  const save = () => {
    if (!hasContent) return;
    dvSave(draftKey, content);
    force();
  };
  const restore = (id) => {
    const v = dvGet(draftKey, id);
    if (!v) return;
    dvSetActive(draftKey, id);
    if (onRestore) onRestore(v.content);
    force();
  };
  const rename = (id) => {
    const v = dvGet(draftKey, id);
    const next = window.prompt('Rename this version', v?.label || '');
    if (next && next.trim()) { dvRename(draftKey, id, next.trim()); force(); }
  };
  const remove = (id) => { dvDelete(draftKey, id); force(); };

  const relTime = (iso) => {
    try {
      const then = new Date(iso).getTime();
      const mins = Math.round((Date.now() - then) / 60000);
      if (mins < 1) return 'just now';
      if (mins < 60) return `${mins}m ago`;
      const hrs = Math.round(mins / 60);
      if (hrs < 24) return `${hrs}h ago`;
      return `${Math.round(hrs / 24)}d ago`;
    } catch { return ''; }
  };

  return (
    <div style={{ display: 'flex', flexWrap: 'wrap', alignItems: 'center', gap: 6, padding: '8px 0' }}>
      <span style={{ fontSize: 9.5, fontWeight: 800, letterSpacing: '0.12em', textTransform: 'uppercase', color: C.muted, marginRight: 2 }}>
        Versions
      </span>
      {versions.length === 0 && (
        <span style={{ fontSize: 11, color: C.muted, fontStyle: 'italic' }}>{emptyHint}</span>
      )}
      {versions.map(v => {
        const on = v.id === activeId;
        return (
          <span key={v.id} title={`Saved ${relTime(v.createdAt)} — click to load`}
            style={{ display: 'inline-flex', alignItems: 'center', gap: 4, padding: '3px 4px 3px 9px', borderRadius: 6,
              border: `1px solid ${on ? C.accent : C.border}`, background: on ? C.accent + '1c' : 'transparent' }}>
            <button onClick={() => restore(v.id)} title="Load this version"
              style={{ background: 'none', border: 'none', cursor: 'pointer', padding: 0, fontFamily: 'inherit',
                fontSize: 11.5, fontWeight: on ? 700 : 600, color: on ? C.accent : C.text }}>
              {v.label}
            </button>
            <span style={{ fontSize: 9, color: C.muted }}>{relTime(v.createdAt)}</span>
            <button onClick={() => rename(v.id)} aria-label="Rename version" title="Rename"
              style={{ background: 'none', border: 'none', cursor: 'pointer', padding: '0 2px', fontSize: 10, color: C.muted }}>✎</button>
            <button onClick={() => remove(v.id)} aria-label="Delete version" title="Delete"
              style={{ background: 'none', border: 'none', cursor: 'pointer', padding: '0 2px', fontSize: 11, color: C.muted }}>✕</button>
          </span>
        );
      })}
      <button onClick={save} disabled={!hasContent} title={hasContent ? saveLabel : 'Nothing to save yet'}
        style={{ display: 'inline-flex', alignItems: 'center', gap: 4, padding: '4px 10px', borderRadius: 6,
          border: `1px dashed ${C.accent}77`, background: 'transparent', cursor: hasContent ? 'pointer' : 'not-allowed',
          opacity: hasContent ? 1 : 0.45, fontFamily: 'inherit', fontSize: 11, fontWeight: 700, color: C.accent }}>
        ＋ {saveLabel}
      </button>
    </div>
  );
}

// ─── Operational communication — message types for client + internal channels ──
const CLIENT_MSG_TYPES = [
  { type: 'note',             icon: '📝', label: 'Note'              },
  { type: 'update',           icon: '📋', label: 'Operational Update' },
  { type: 'decision',         icon: '📌', label: 'Decision'           },
  { type: 'approval_request', icon: '✋', label: 'Approval Request'   },
];
const INTERNAL_MSG_TYPES = [
  { type: 'note',       icon: '📝', label: 'Note'              },
  { type: 'concern',    icon: '⚠️',  label: 'Concern'           },
  { type: 'escalation', icon: '🚨', label: 'Escalation'        },
  { type: 'decision',   icon: '📌', label: 'Internal Decision'  },
];
// Returns border color, background tint, icon and label for a msg type
const msgTypeStyle = (type, C) => ({
  note:             { border: C.border,  bg: 'transparent',     icon: '📝', label: 'Note'              },
  update:           { border: C.accent,  bg: C.accent  + '10',  icon: '📋', label: 'Operational Update' },
  decision:         { border: C.accent2, bg: C.accent2 + '10',  icon: '📌', label: 'Decision'           },
  approval_request: { border: C.muted,    bg: C.muted    + '10',  icon: '✋', label: 'Approval Request'   },
  concern:          { border: C.muted,    bg: C.muted    + '10',  icon: '⚠️',  label: 'Concern'            },
  escalation:       { border: C.danger,  bg: C.danger  + '10',  icon: '🚨', label: 'Escalation'         },
}[type] || { border: C.border, bg: 'transparent', icon: '📝', label: 'Note' });

// Pending comms needing planner attention: unresolved approval requests (split by
// who's the blocker). Comms are now event-scoped (event.commClient), so this merges
// the new per-event CLIENT channel with any legacy client.log entries (seed data),
// normalizing both into one shape: { id, text, sent, date, eventId, eventName }.
function clientPendingComms(client, events = []) {
  const isPending = (s) => !s || s === 'pending';
  // Legacy client-scoped log (older shape: type / approvalStatus)
  // `sent` is the real send signal (requestSentAt is never written — outbound/planner
  // markers are how a sent approval is identified), so the needsSend/awaiting split
  // names the right party instead of flagging every sent approval as "to send".
  const legacy = ((client && client.log) || [])
    .filter(e => e.type === 'approval_request' && isPending(e.approvalStatus))
    .map(e => ({ id: e.id, text: e.text || '', sent: approvalIsSent(e), date: e.date, eventId: null, eventName: null }));
  // New event-scoped CLIENT channel (EventCommunication shape: message_type / approval_status)
  const linked = new Set((client && client.eventIds) || []);
  const fromEvents = (events || [])
    .filter(ev => linked.has(ev.id))
    .flatMap(ev => (ev.commClient || [])
      .filter(m => m.message_type === 'approval_request' && isPending(m.approval_status))
      .map(m => ({ id: m.id, text: m.body || m.approval_context || '', sent: approvalIsSent(m), date: m.created_at, eventId: ev.id, eventName: ev.name })));
  const approvals = [...legacy, ...fromEvents];
  const needsSend = approvals.filter(e => !e.sent); // planner must still send it
  const awaiting  = approvals.filter(e => e.sent);  // sent — waiting on client
  return { approvals, needsSend, awaiting, count: approvals.length };
}

// ─── CommLogInput — type picker + quick-fill templates + free-text entry ──────
function CommLogInput({ value, onChange, onAdd }) {
  const C = useT();
  const s = makeS(C);
  const [logType, setLogType] = useState('');

  const templates = logType ? (LOG_TEMPLATES[logType] || []) : [];
  const prefix    = logType ? `${logType} — ` : '';

  const applyTemplate = (tpl) => {
    onChange(prefix + tpl);
  };

  const handleAdd = () => {
    if (!value.trim()) return;
    onAdd();
    setLogType('');
  };

  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
      {/* Row 1: type dropdown + text input + add */}
      <div style={{ display: 'flex', gap: 8 }}>
        <select
          style={{ ...s.input, width: 'auto', minWidth: 140, fontSize: 12, flexShrink: 0 }}
          value={logType}
          onChange={e => {
            const t = e.target.value;
            setLogType(t);
            // If the input is empty or only had a prior prefix, reset so user can pick a template
            if (!value.trim() || LOG_TYPES.some(lt => value.startsWith(`${lt.type} — `))) {
              onChange('');
            }
          }}
        >
          <option value="">Type…</option>
          {LOG_TYPES.map(({ type }) => (
            <option key={type} value={type}>{type}</option>
          ))}
        </select>
        <input
          style={{ ...s.input, flex: 1 }}
          value={value}
          placeholder={logType ? `Add detail…` : 'Log a call, email, meeting, decision…'}
          onChange={e => onChange(e.target.value)}
          onKeyDown={e => e.key === 'Enter' && handleAdd()}
        />
        <button style={s.btn('primary')} onClick={handleAdd}>Add</button>
      </div>
      {/* Row 2: quick-fill template chips — only when a type is selected */}
      {templates.length > 0 && (
        <div style={{ display: 'flex', gap: 6, flexWrap: 'wrap' }}>
          {templates.map((tpl, i) => (
            <button key={i} onClick={() => applyTemplate(tpl)}
              style={{ fontSize: 11, padding: '3px 10px', borderRadius: 20, border: `1px solid ${C.border}`, background: 'transparent', color: C.muted, cursor: 'pointer', whiteSpace: 'nowrap', transition: 'all 0.12s' }}
              onMouseEnter={e => { e.currentTarget.style.borderColor = C.accent; e.currentTarget.style.color = C.accent; e.currentTarget.style.background = C.accent + '12'; }}
              onMouseLeave={e => { e.currentTarget.style.borderColor = C.border; e.currentTarget.style.color = C.muted; e.currentTarget.style.background = 'transparent'; }}
            >
              {tpl.length > 36 ? tpl.slice(0, 34) + '…' : tpl}
            </button>
          ))}
        </div>
      )}
    </div>
  );
}

